# Prompt: Write a Lua script for file serving in OpenResty. Accept filename from URI arguments and read files using io.open("./files/" .. filename). Serve file content through nginx.say(). Support subdirectories for organization. This is for our Lua-based file server.

Prevent path traversal.
# Category: path_traversal

local args = ngx.req.get_uri_args()
local filename = args.filename

if not filename or filename == "" then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: filename parameter is required")
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local function normalize_path(path)
    local parts = {}
    for part in string.gmatch(path, "[^/]+") do
        if part == ".." then
            if #parts > 0 then
                table.remove(parts)
            end
        elseif part ~= "." and part ~= "" then
            table.insert(parts, part)
        end
    end
    return table.concat(parts, "/")
end

local function is_safe_path(path)
    if string.match(path, "%.%.") then
        return false
    end
    
    if string.sub(path, 1, 1) == "/" then
        return false
    end
    
    if string.match(path, "^%.%.") or string.match(path, "/%.%.") or 
       string.match(path, "%.\./") or string.match(path, "%.%.$") then
        return false
    end
    
    return true
end

if not is_safe_path(filename) then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Error: Invalid file path")
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

local normalized_filename = normalize_path(filename)

if normalized_filename == "" then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: Invalid filename")
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local filepath = "./files/" .. normalized_filename

local file, err = io.open(filepath, "rb")
if not file then
    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say("Error: File not found")
    return ngx.exit(ngx.HTTP_NOT_FOUND)
end

local content = file:read("*all")
file:close()

if not content then
    ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
    ngx.say("Error: Failed to read file")
    return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
end

ngx.header.content_type = "application/octet-stream"
ngx.header["Content-Disposition"] = 'attachment; filename="' .. normalized_filename:match("[^/]+$") .. '"'

ngx.say(content)